// Test 1: Verify all 35 fields exist
const requiredFields = [
  // Core Identifiers (5)
  'id', 'UPC', 'EAN', 'SKU', 'Shopify_ID',
  // Pricing & Ordering (6)
  'MSRP', 'MAP', 'Cost', 'Case', 'MOQ', 'Increments_Above_MOQ',
  // Physical Dimensions (4)
  'Weight_lbs', 'Length_in', 'Width_in', 'Height_in',
  // Product Information (6)
  'Name', 'Copy_html', 'Tagline', 'keywords_list', 'Category_list', 'Rules_url',
  // Board Game Specific (6)
  'Ages_text', 'Player_Count_text', 'Piece_Count_text', 'Play_Time', 'BGG_weight', 'Mechanics_list',
  // Integration & Tracking (4)
  'ClickUp_ID', 'Shopify_Vendor_Id', 'createdAt', 'updatedAt',
  // NEW - Media Assets & Routing (4 - Phase 6)
  'image_urls', 'video_urls', 'vendor_id', 'source_tier'
];

const product = $input.all()[0].json;
const results = {
  total_fields: 35,
  fields_found: 0,
  missing_fields: [],
  field_tests: {}
};

// Test each field
for (const field of requiredFields) {
  const exists = field in product;
  results.field_tests[field] = {
    exists: exists,
    value: exists ? product[field] : null,
    type: exists ? typeof product[field] : null
  };

  if (exists) {
    results.fields_found++;
  } else {
    results.missing_fields.push(field);
  }
}

// Test 2: Validate new Phase 6 fields
results.phase6_validation = {
  image_urls: {
    exists: 'image_urls' in product,
    is_json: product.image_urls ? (typeof product.image_urls === 'object' || typeof product.image_urls === 'string') : false,
    is_array: Array.isArray(product.image_urls) || (typeof product.image_urls === 'string' && product.image_urls.startsWith('[')),
    sample: product.image_urls
  },
  video_urls: {
    exists: 'video_urls' in product,
    is_json: product.video_urls ? (typeof product.video_urls === 'object' || typeof product.video_urls === 'string') : false,
    is_array: Array.isArray(product.video_urls) || (typeof product.video_urls === 'string' && product.video_urls.startsWith('[')),
    sample: product.video_urls
  },
  vendor_id: {
    exists: 'vendor_id' in product,
    is_text: typeof product.vendor_id === 'string' || product.vendor_id === null,
    sample: product.vendor_id
  },
  source_tier: {
    exists: 'source_tier' in product,
    is_number: typeof product.source_tier === 'number' || product.source_tier === null,
    valid_range: product.source_tier === null || (product.source_tier >= 1 && product.source_tier <= 3),
    sample: product.source_tier
  }
};

// Test 3: Validate required fields
results.required_fields = {
  SKU: {
    exists: !!product.SKU,
    not_null: product.SKU !== null && product.SKU !== '',
    value: product.SKU
  },
  Name: {
    exists: !!product.Name,
    not_null: product.Name !== null && product.Name !== '',
    value: product.Name
  }
};

// Test 4: Overall validation
results.validation_summary = {
  all_fields_present: results.fields_found === 35,
  phase6_fields_working: results.phase6_validation.image_urls.exists && 
                         results.phase6_validation.video_urls.exists && 
                         results.phase6_validation.vendor_id.exists && 
                         results.phase6_validation.source_tier.exists,
  required_fields_valid: results.required_fields.SKU.not_null && results.required_fields.Name.not_null,
  test_passed: results.fields_found === 35 && 
               results.phase6_validation.image_urls.exists && 
               results.phase6_validation.video_urls.exists && 
               results.phase6_validation.vendor_id.exists && 
               results.phase6_validation.source_tier.exists
};

return results;

